    public function get_icon($key, $label, $svg) {
        $url = techpress_setting($key, '');
        if (!$url) {
            return '';
        }
        return '<a href="' . esc_url($url) . '" target="_blank" rel="nofollow noopener" title="' . esc_attr($label) . '">' . $svg . '</a>';
    }

    public function get_links() {
        $output = '';
        foreach ($this->providers as $key => $data) {
            $output .= $this->get_icon($key, $data['label'], $data['svg']);
        }
        return $output;
    }

    public function render_footer() {
        $links = $this->get_links();
        if ($links) {
            echo '<div class="footer-social">' . $links . '</div>';
        }
    }
}
